The load_subjects table needs to be created on live, I have written the create query below, and then the query that I think will let you insert the data from local to live and then run the other queries after these two.

CREATE TABLE STPETERSBURG.LOAD_SUBJECTS 
(
  REF_NBR NUMBER(6, 2) 
, DISCIPLINE_DESCRIPTION VARCHAR2(58 BYTE) 
, PREFIX VARCHAR2(85 BYTE) 
);

INSERT INTO stpetersburg.load_subjects(ref_nbr, discipline_description, prefix)
(SELECT ref_nbr, discipline_description, prefix
 FROM stpetersburg.load_subjects@oraclesup_link.governet.LOCAL);

ALTER TABLE STPETERSBURG.SUBJECTS
ADD (REFERENCE_NUMBER NUMBER(6, 2) );

UPDATE stpetersburg.subjects s
SET s.reference_number = (SELECT ls.ref_nbr
FROM stpetersburg.load_subjects ls
WHERE s.subject_code = ls.prefix);

UPDATE stpetersburg.courses c
SET c.disc_ref_num = (SELECT s.reference_number
FROM stpetersburg.subjects s
WHERE c.subjects_id = s.subjects_id);

QUERIES FOR LIVE:
ALTER TABLE STPETERSBURG.FIN_AID_STATUS  
